import pika
import subprocess

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        # Validate the command to ensure it's safe to execute
        allowed_commands = ['ls', 'echo', 'date']  # Example of allowed commands
        if command.split()[0] in allowed_commands:
            result = subprocess.run(command, shell=True, check=True, text=True, capture_output=True)
            print(f"Command executed successfully: {result.stdout}")
        else:
            print(f"Command not allowed: {command}")
    except subprocess.CalledProcessError as e:
        print(f"Error executing command: {e}")
    except Exception as e:
        print(f"Unexpected error: {e}")

def main():
    connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
    channel = connection.channel()
    channel.queue_declare(queue='job_queue')

    channel.basic_consume(queue='job_queue', on_message_callback=callback, auto_ack=True)
    print('Waiting for messages. To exit press CTRL+C')
    channel.start_consuming()

if __name__ == '__main__':
    main()